    expertId: string
    conversationId: string
    expertName: string
    expertTitle: string
    expertSpecialization: string
}

export function ChatOrchestrator({ dossier }: ChatOrchestratorProps) {
    const [mode, setMode] = useState<ChatMode>('XO')
    const [activeSession, setActiveSession] = useState<ActiveSession | null>(null)

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const handleMandate = (expert: any, conversationId: string) => {
        setActiveSession({
            expertId: expert.id,
            conversationId,
            expertName: expert.name,
            expertTitle: expert.title,
            expertSpecialization: expert.specialization,
        })
        setMode('EXPERT')
    }

    const handleExpertComplete = () => {
        setMode('XO')
        setActiveSession(null)
        // Optionally trigger XO to synthesize results here?
        // For now, just returning to XO view.
    }

    if (mode === 'EXPERT' && activeSession) {
        return (
            <ExpertChat
                expert={{
                    id: activeSession.expertId,
                    name: activeSession.expertName,
                    title: activeSession.expertTitle,
                    specialization: activeSession.expertSpecialization,
                }}
                conversationId={activeSession.conversationId}
                onComplete={handleExpertComplete}
            />
        )
    }

    return (
        <XOChat
            dossier={dossier}
            onMandate={handleMandate}
        />
    )
}

