import { useState, useEffect } from 'react'

export interface DossierWithCards {
    id: string
    title: string
    cards: Array<{
        id: string
        type: string
        title: string
        content: any
        positionX: number
        positionY: number
        state: string
        axisLink?: string
        createdBy?: string
    }>
    [key: string]: any
}

export function useDossier(id: string | undefined) {
    const [dossier, setDossier] = useState<DossierWithCards | null>(null)
    const [isLoading, setIsLoading] = useState(true)
    const [error, setError] = useState<string | null>(null)

    useEffect(() => {
        if (!id) {
            setIsLoading(false)
            return
        }

        const fetchDossier = async () => {
            try {
                const response = await fetch(`/api/dossiers/${id}`)
                if (!response.ok) {
                    console.warn('Failed to fetch dossier from API')
                    setDossier(null)
                    return
                }
                const data = await response.json()
                setDossier(data)
            } catch (err) {
                console.error(err)
                setError('Failed to load dossier')
            } finally {
                setIsLoading(false)
            }
        }

        fetchDossier()

        const interval = setInterval(fetchDossier, 5000) // Poll every 5 seconds for updates (e.g. new cards from experts)

        return () => clearInterval(interval)
    }, [id])

    return { dossier, isLoading, error }
}

