import { NextRequest, NextResponse } from 'next/server'
import { getAuthUser, handleAuthError } from '@/lib/auth-helpers'
import { prisma } from '@/lib/prisma'
import type { AnalysisOutput } from '@/lib/analysis/types'
import type { Prisma } from '@prisma/client'
import { nanoid } from 'nanoid'

export async function POST(req: NextRequest) {
    try {
        // Get authenticated user
        const user = await getAuthUser()

        // Parse request body
        const analysisOutput: AnalysisOutput = await req.json()

        // Extract data from AnalysisOutput
        const { idea, analysis, scores, decision } = analysisOutput

        // Build scores object from the 6 axes
        const axisScores = {
            problem: analysis.problem.score,
            market: analysis.market.score,
            differentiation: analysis.differentiation.score,
            feasibility: analysis.feasibility.score,
            business: analysis.business.score,
            founder_fit: analysis.founder_fit.score,
            global_score: scores.global_score
        }

        // Create project with workspace in a transaction
        const result = await prisma.$transaction(async (tx) => {
            // Create project
            const project = await tx.projects.create({
                data: {
                    id: nanoid(),
                    user_id: user.id,
                    name: idea.title,
                    description: idea.raw_summary,
                    status: 'IDEATION',
                    phase: 'CAPTURE',
                    score: scores.global_score,
                    scores: JSON.parse(JSON.stringify(axisScores)) as Prisma.InputJsonValue,
                    analysis_data: JSON.parse(JSON.stringify(analysisOutput)) as Prisma.InputJsonValue,
                    updated_at: new Date()
                }
            })

            // Create default workspace for the project
            const workspace = await tx.workspaces.create({
                data: {
                    id: nanoid(),
                    project_id: project.id,
                    view_settings: {},
                    updated_at: new Date()
                }
            })

            return { project, workspace }
        })

        // Return created project
        return NextResponse.json({
            projectId: result.project.id,
            project: result.project
        }, { status: 201 })

    } catch (error) {
        return handleAuthError(error)
    }
}

