'use client'

import { useState, useEffect, useCallback } from 'react'

export interface Card {
    id: string
    workspace_id: string
    type: string
    label: string
    description: string | null
    position: { x: number; y: number }
    phase: string | null
    status: string
    priority: string
    metadata: Record<string, any>
    tags: string[]
    validated: boolean
    validated_at: Date | null
    created_at: Date
    updated_at: Date
}

export interface UseCardsOptions {
    projectId: string
    type?: string
    phase?: string
    status?: string
    autoRefresh?: boolean
    refreshInterval?: number
}

export function useCards({
    projectId,
    type,
    phase,
    status,
    autoRefresh = false,
    refreshInterval = 5000
}: UseCardsOptions) {
    const [cards, setCards] = useState<Card[]>([])
    const [isLoading, setIsLoading] = useState(true)
    const [error, setError] = useState<string | null>(null)

    const fetchCards = useCallback(async () => {
        try {
            const params = new URLSearchParams()
            if (type) params.append('type', type)
            if (phase) params.append('phase', phase)
            if (status) params.append('status', status)

            const url = `/api/projects/${projectId}/cards?${params.toString()}`
            const response = await fetch(url)

            if (!response.ok) {
                throw new Error('Failed to fetch cards')
            }

            const data = await response.json()
            setCards(data.data || [])
            setError(null)
        } catch (err) {
            console.error('Error fetching cards:', err)
            setError(err instanceof Error ? err.message : 'Failed to load cards')
        } finally {
            setIsLoading(false)
        }
    }, [projectId, type, phase, status])

    useEffect(() => {
        fetchCards()

        if (autoRefresh) {
            const interval = setInterval(fetchCards, refreshInterval)
            return () => clearInterval(interval)
        }
    }, [fetchCards, autoRefresh, refreshInterval])

    const createCard = useCallback(async (cardData: {
        type: string
        label: string
        content?: string
        status?: string
        priority?: string
        position?: { x: number; y: number }
        phase?: string
        metadata?: Record<string, any>
        tags?: string[]
    }) => {
        try {
            const response = await fetch(`/api/projects/${projectId}/cards`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(cardData)
            })

            if (!response.ok) {
                throw new Error('Failed to create card')
            }

            const data = await response.json()
            const newCard = data.data

            setCards(prev => [...prev, newCard])
            return newCard
        } catch (err) {
            console.error('Error creating card:', err)
            throw err
        }
    }, [projectId])

    const updateCard = useCallback(async (cardId: string, updates: Partial<{
        type: string
        label: string
        content: string
        status: string
        priority: string
        position: { x: number; y: number }
        phase: string
        metadata: Record<string, any>
        tags: string[]
        validated: boolean
    }>) => {
        try {
            const response = await fetch(`/api/cards/${cardId}`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(updates)
            })

            if (!response.ok) {
                throw new Error('Failed to update card')
            }

            const data = await response.json()
            const updatedCard = data.data

            setCards(prev => prev.map(card =>
                card.id === cardId ? updatedCard : card
            ))
            return updatedCard
        } catch (err) {
            console.error('Error updating card:', err)
            throw err
        }
    }, [])

    const deleteCard = useCallback(async (cardId: string) => {
        try {
            const response = await fetch(`/api/cards/${cardId}`, {
                method: 'DELETE'
            })

            if (!response.ok) {
                throw new Error('Failed to delete card')
            }

            setCards(prev => prev.filter(card => card.id !== cardId))
        } catch (err) {
            console.error('Error deleting card:', err)
            throw err
        }
    }, [])

    const refresh = useCallback(() => {
        setIsLoading(true)
        fetchCards()
    }, [fetchCards])

    return {
        cards,
        isLoading,
        error,
        createCard,
        updateCard,
        deleteCard,
        refresh
    }
}

