import { NextRequest, NextResponse } from 'next/server'
import { getAuthUser, verifyProjectOwnership, handleAuthError } from '@/lib/auth-helpers'
import { prisma } from '@/lib/prisma'

/**
 * GET /api/projects/[id]
 * Get a single project by ID
 */
export async function GET(
    req: NextRequest,
    { params }: { params: Promise<{ id: string }> }
) {
    try {
        const user = await getAuthUser()
        const { id } = await params

        // Verify project ownership
        const project = await verifyProjectOwnership(id, user.id)

        return NextResponse.json({
            success: true,
            data: project
        })
    } catch (error) {
        console.error('Get project error:', error)
        return handleAuthError(error)
    }
}

/**
 * PATCH /api/projects/[id]
 * Update a project
 */
export async function PATCH(
    req: NextRequest,
    { params }: { params: Promise<{ id: string }> }
) {
    try {
        const user = await getAuthUser()
        const { id } = await params

        // Verify project ownership
        await verifyProjectOwnership(id, user.id)

        // Parse request body
        const body = await req.json()
        const { name, description, status, phase, category } = body

        // Build update data
        const updateData: any = {
            updated_at: new Date()
        }

        if (name !== undefined) updateData.name = name
        if (description !== undefined) updateData.description = description
        if (status !== undefined) updateData.status = status
        if (phase !== undefined) updateData.phase = phase
        if (category !== undefined) updateData.category = category

        // Update project
        const updatedProject = await prisma.projects.update({
            where: { id },
            data: updateData
        })

        return NextResponse.json({
            success: true,
            data: updatedProject
        })
    } catch (error) {
        console.error('Update project error:', error)
        return handleAuthError(error)
    }
}

/**
 * DELETE /api/projects/[id]
 * Soft delete a project
 */
export async function DELETE(
    req: NextRequest,
    { params }: { params: Promise<{ id: string }> }
) {
    try {
        const user = await getAuthUser()
        const { id } = await params

        // Verify project ownership
        await verifyProjectOwnership(id, user.id)

        // Soft delete (set deleted_at timestamp)
        await prisma.projects.update({
            where: { id },
            data: {
                deleted_at: new Date(),
                updated_at: new Date()
            }
        })

        return NextResponse.json({
            success: true,
            message: 'Project deleted successfully'
        })
    } catch (error) {
        console.error('Delete project error:', error)
        return handleAuthError(error)
    }
}

