import { useState, useEffect } from "react";
import type { AnalysisOutput } from "@/lib/analysis/types";

export interface StoredProject {
    id: string;
    title: string;
    text: string;
    description: string;
    globalScore: number;
    recommendation: "GO" | "EXPLORE" | "PARK" | "KILL";
    confidenceLevel: "LOW" | "MEDIUM" | "HIGH";
    analysis: {
        axes: Array<{ label: string; score: number; justification?: string }>;
        synthesis: string;
        risks: string[];
    };
    timestamp: string;
    isDemo: boolean;
    fullResult?: AnalysisOutput;
}

export function useProject(id: string | undefined) {
    const [project, setProject] = useState<StoredProject | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        if (!id) {
            setIsLoading(false);
            return;
        }

        async function fetchProject() {
            try {
                setIsLoading(true);
                const response = await fetch(`/api/projects/${id}`);

                if (!response.ok) {
                    // Try localStorage fallback for demo/legacy projects
                    const localProject = tryLocalStorageFallback(id);
                    if (localProject) {
                        setProject(localProject);
                        setIsLoading(false);
                        return;
                    }

                    throw new Error('Failed to fetch project');
                }

                const data = await response.json();
                const apiProject = data.data;

                // Convert API project to StoredProject format
                setProject(apiProjectToStoredProject(apiProject));
                setError(null);
            } catch (err) {
                console.error('Error fetching project:', err);
                setError(err instanceof Error ? err.message : 'Failed to load project');

                // Final fallback to localStorage
                const localProject = tryLocalStorageFallback(id);
                if (localProject) {
                    setProject(localProject);
                } else {
                    setProject(null);
                }
            } finally {
                setIsLoading(false);
            }
        }

        fetchProject();
    }, [id]);

    return { project, isLoading, error };
}

function normalizeProject(raw: any): StoredProject {
    return {
        id: raw.id || "",
        title: raw.title || raw.text || "Untitled",
        text: raw.text || "",
        description: raw.description || raw.text || "",
        globalScore: raw.globalScore ?? raw.viabilityScore ?? 0,
        recommendation: raw.recommendation ?? raw.classification ?? "EXPLORE",
        confidenceLevel: raw.confidenceLevel ?? "MEDIUM",
        analysis: {
            axes: raw.analysis?.axes ?? [],
            synthesis: raw.analysis?.synthesis ?? "",
            risks: raw.analysis?.risks ?? [],
        },
        timestamp: raw.timestamp || new Date().toISOString(),
        isDemo: raw.isDemo ?? false,
        fullResult: raw.fullResult ?? undefined,
    };
}

